import React, { useState } from "react";
import { Link, useNavigate, useLocation } from "react-router-dom";

export default function Sidebar() {
  const navigate = useNavigate();
  const location = useLocation(); // Para saber qué ruta está activa
  const [openVentas, setOpenVentas] = useState(false);

  const handleLogout = () => {
    // Limpiamos todo el rastro de la sesión
    localStorage.clear(); 
    navigate("/");
  };

  // Función para determinar si un enlace está activo y darle estilo
  const isActive = (path) => location.pathname === path ? "bg-primary shadow" : "";

  return (
    <div
      className="d-flex flex-column p-3 text-white"
      style={{
        width: "250px",
        height: "100vh",
        background: "#1a1a1a",
        position: "fixed",
        left: 0,
        top: 0,
        boxShadow: "4px 0 10px rgba(0,0,0,0.3)",
        zIndex: 1100
      }}
    >
      <div className="text-center mb-4 pt-2">
        <h4 className="fw-bold text-uppercase tracking-wider">
          <span className="text-primary">Pos</span>System
        </h4>
        <hr className="bg-secondary" />
      </div>

      <ul className="nav nav-pills flex-column mb-auto gap-1">
        
        <li className="nav-item">
          <Link className={`nav-link text-white d-flex align-items-center ${isActive("/dashboard")}`} to="/dashboard">
            <span className="me-2">📊</span> Dashboard
          </Link>
        </li>

        <li className="nav-item">
          <Link className={`nav-link text-white d-flex align-items-center ${isActive("/productos")}`} to="/productos">
            <span className="me-2">📦</span> Productos
          </Link>
        </li>

        <li className="nav-item">
          <Link className={`nav-link text-white d-flex align-items-center ${isActive("/categorias")}`} to="/categorias">
            <span className="me-2">📁</span> Categorías
          </Link>
        </li>

        <li className="nav-item">
          <Link className={`nav-link text-white d-flex align-items-center ${isActive("/clientes")}`} to="/clientes">
            <span className="me-2">👥</span> Clientes
          </Link>
        </li>

        {/* --- MENÚ DE VENTAS CON SUBMENÚ --- */}
        <li className="nav-item">
          <button
            className="btn text-white w-100 text-start d-flex justify-content-between align-items-center p-2"
            onClick={() => setOpenVentas(!openVentas)}
            style={{ borderRadius: 'var(--bs-nav-pills-border-radius)' }}
          >
            <span><span className="me-2">💰</span> Ventas</span>
            <small>{openVentas ? "▲" : "▼"}</small>
          </button>

          {openVentas && (
            <ul className="nav flex-column ms-3 mt-1 gap-1 border-start border-secondary border-opacity-25">
              <li>
                <Link className={`nav-link text-white small ${isActive("/ventas")}`} to="/ventas">
                  • Registrar Venta
                </Link>
              </li>
              <li>
                <Link className={`nav-link text-white small ${isActive("/ventas-historial")}`} to="/ventas-historial">
                  • Ver Registro
                </Link>
              </li>
            </ul>
          )}
        </li>
        
        <li className="nav-item">
          <Link className={`nav-link text-white d-flex align-items-center ${isActive("/reportes")}`} to="/reportes">
            <span className="me-2">📈</span> Reportes
          </Link>
        </li>

        <li className="nav-item">
          <Link className={`nav-link text-white d-flex align-items-center ${isActive("/usuarios")}`} to="/usuarios">
            <span className="me-2">👤</span> Usuarios
          </Link>
        </li>
      </ul>

      <div className="mt-auto pt-3 border-top border-secondary">
        <button
          onClick={handleLogout}
          className="btn btn-outline-danger w-100 fw-bold d-flex align-items-center justify-content-center"
        >
          <span className="me-2">🚪</span> Cerrar sesión
        </button>
      </div>

      {/* CSS interno para efectos de hover */}
      <style>{`
        .nav-link:hover {
          background-color: rgba(255, 255, 255, 0.1);
          color: #0d6efd !important;
        }
        .nav-link.active {
          background-color: #0d6efd !important;
          color: white !important;
        }
      `}</style>
    </div>
  );
}
